#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for stale sensor data - if either sensor is stale for more than 1000ms, go to safe all-off state */
    bool has_stale_sensor = false;
    if (!controller->has_valid_temperature && !controller->last_temperature_ms) {
        has_stale_sensor = true;
    } else if (controller->has_valid_temperature && controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        has_stale_sensor = true;
    }

    if (!controller->has_valid_level && !controller->last_level_ms) {
        has_stale_sensor = true;
    } else if (controller->has_valid_level && controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        has_stale_sensor = true;
    }

    /* Stay in the safe all-off state until both sensors have been seen validly */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* If either sensor becomes stale for more than 1000 ms, go to the safe all-off state */
    if (has_stale_sensor) {
        controller_set_safe_idle(controller);
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
        return output;
    }

    /* Control policy implementation */
    int level = controller->last_level;
    int temp = controller->last_temperature_c;

    /* On boot, keep the inlet closed and the heater off (already set to safe idle) */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        /* If LEVEL < 60, command INLET OPEN and HEATER OFF */
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
        output.state_name = controller_state_name(CONTROLLER_STATE_FILLING);
    } else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* If LEVEL > 75, command INLET CLOSED */
        controller->inlet_open = false;
        /* Heater state depends on temperature below */
    }

    /* If LEVEL < 55 at any time, keep HEATER OFF */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        controller->heater_on = false;
    } else if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
        /* Safe level with low temperature: INLET CLOSED and HEATER ON */
        controller->inlet_open = false;
        controller->heater_on = true;
        controller->state = CONTROLLER_STATE_HEATING;
        output.state_name = controller_state_name(CONTROLLER_STATE_HEATING);
    } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
        /* If 45 <= TEMP < 47, command INLET CLOSED and hold the previous safe heater state */
        controller->inlet_open = false;
        /* Hold previous heater state - if we were heating, stay heating */
        if (previous_heater_on) {
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
    } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* If 47 <= TEMP <= 48, check temperature trend */
        bool is_rising = false;
        if (controller->previous_temperature_c != 0) {
            is_rising = temp > controller->previous_temperature_c;
        }

        if (is_rising) {
            /* Rising temperature: command HEATER OFF early */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
            output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
        } else {
            /* Not rising: hold the previous safe heater state */
            if (previous_heater_on) {
                controller->heater_on = true;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
            output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
        }
    } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* If TEMP > 48, command INLET CLOSED and HEATER OFF */
        controller->inlet_open = false;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE);
    }

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

