    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for stale sensor data - if either sensor is stale for more than 1000ms, go to safe all-off state */
    bool has_stale_sensor = false;
    if (!controller->has_valid_temperature && !controller->last_temperature_ms) {
        has_stale_sensor = true;
    } else if (controller->has_valid_temperature && controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
        has_stale_sensor = true;
    }

    if (!controller->has_valid_level && !controller->last_level_ms) {
        has_stale_sensor = true;
