            controller->state = CONTROLLER_STATE_HOLDING;
        } else {
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
        }
        output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
    } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
        /* If 47 <= TEMP <= 48, check temperature trend */
        bool is_rising = false;
        if (controller->previous_temperature_c != 0) {
            is_rising = temp > controller->previous_temperature_c;
        }

        if (is_rising) {
            /* Rising temperature: command HEATER OFF early */
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_HOLDING;
            output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
        } else {
